<template>
  <AppGridLayout title="Photography" :elements="photosList" padless :minHeightPresent="false">
    <template v-slot="{ element: p }" #default>
      <div>
        <v-img
          :src="require(`@/assets/images/${p.fileName}`)"
          :alt="p.alt"
        >
          <template #placeholder>
            <v-row class="fill-height ma-0" align="center" justify="center">
              <v-progress-circular indeterminate color="grey lighten-5"></v-progress-circular>
            </v-row>
          </template>
        </v-img>
      </div>
    </template>
  </AppGridLayout>
</template>

<script>
import AppGridLayout from "@/components/AppGridLayout.vue";

export default {
  name: "Photography",
  components: {
    AppGridLayout
  },
  data() {
    return {
      photosQuantity: 6
    };
  },
  computed: {
    photosList() {
      return Array(this.photosQuantity)
        .fill()
        .map((e, i) =>
          Object({
            fileName: `${i + 1}.jpg`,
            alt: `Photo ${i + 1}`
          })
        );
    }
  },
  mounted() {
    this.$vuetify.theme.dark = true;
  },
  beforeDestroy() {
    this.$vuetify.theme.dark = false;
  }
};
</script>

<style scoped>
@media (max-width: 600px) {
  ::v-deep .grid-title {
    font-size: 14vw !important;
  }
}
</style>
